#!/usr/bin/env node
/**
 * Generates src/main/register-aliases.ts from tsconfig.electron.json paths.
 *
 * Run: node scripts/generate-register-aliases.js
 * Hooked into prebuild/prestart via package.json.
 *
 * The generated file is committed so diffs reveal alias additions/removals.
 * The canonical source of truth is tsconfig.electron.json compilerOptions.paths.
 */

'use strict';

const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');
const TSCONFIG_PATH = path.join(ROOT, 'tsconfig.electron.json');
const OUTPUT_PATH = path.join(ROOT, 'src', 'main', 'register-aliases.ts');

/**
 * Base dir that tsconfig.electron.json uses for each prefix, expressed
 * as the variable name in register-aliases.ts and its tsconfig-relative prefix.
 */
const BASE_DIR_MAP = [
  { varName: 'baseContracts', tsconfigPrefix: 'packages/contracts/src' },
  { varName: 'baseSdk',       tsconfigPrefix: 'packages/sdk/src' },
  { varName: 'baseShared',    tsconfigPrefix: 'src/shared' },
];

// Wildcard prefixes: @alias/* entries resolved via prefixAliases
const WILDCARD_PREFIXES = {
  '@contracts': 'baseContracts',
  '@sdk':       'baseSdk',
  '@shared':    'baseShared',
};

/**
 * Strips a leading "./" and a trailing element of the form "*" or "index".
 * Returns the base dir path (relative to repo root) or null if unrecognised.
 */
function toTsconfigBase(firstTarget) {
  const t = firstTarget.replace(/^\.\//, '');
  // Wildcard aliases end with "/*" — strip
  if (t.endsWith('/*')) return t.slice(0, -2);
  // Bare index aliases end with "/index" — strip
  if (t.endsWith('/index')) return t.slice(0, -'/index'.length);
  return t;
}

/**
 * Converts a tsconfig path entry target like
 *   "./packages/contracts/src/schemas/common.schemas"
 * to a JS expression using the named base variable like
 *   "path.join(baseContracts, 'schemas', 'common.schemas')"
 */
function targetToExpression(target) {
  const tRelative = target.replace(/^\.\//, '');

  for (const { varName, tsconfigPrefix } of BASE_DIR_MAP) {
    if (tRelative.startsWith(tsconfigPrefix + '/')) {
      const rest = tRelative.slice(tsconfigPrefix.length + 1);
      const parts = rest.split('/').map((p) => `'${p}'`).join(', ');
      return `path.join(${varName}, ${parts})`;
    }
    if (tRelative === tsconfigPrefix) {
      return varName;
    }
  }

  // Fallback: use path.join(__dirname, '..', ...segments)
  const parts = tRelative.split('/').map((p) => `'${p}'`).join(', ');
  return `path.join(__dirname, '..', ${parts})`;
}

function main() {
  const raw = fs.readFileSync(TSCONFIG_PATH, 'utf-8');
  // Strip // comments so JSON.parse works
  const stripped = raw.replace(/\/\/[^\n]*/g, '');
  const tsconfig = JSON.parse(stripped);
  const paths = tsconfig?.compilerOptions?.paths ?? {};

  const exactLines = [];
  const wildcardLines = [];

  for (const [alias, targets] of Object.entries(paths)) {
    const target = targets[0];
    if (!target) continue;

    const isWildcard = alias.endsWith('/*');
    if (isWildcard) {
      const base = toTsconfigBase(target);
      let varNameOrExpr = null;
      for (const { varName, tsconfigPrefix } of BASE_DIR_MAP) {
        if (base === tsconfigPrefix) {
          varNameOrExpr = varName;
          break;
        }
      }
      if (!varNameOrExpr) {
        varNameOrExpr = targetToExpression(target);
      }
      const prefix = alias.slice(0, -2);
      wildcardLines.push({ prefix, expr: varNameOrExpr });
      continue;
    }

    // Bare prefix alias (e.g. "@contracts" → "./packages/contracts/src/index")
    if (!alias.includes('*')) {
      const base = toTsconfigBase(target);
      let isBarePrefix = false;
      for (const { varName, tsconfigPrefix } of BASE_DIR_MAP) {
        if (base === tsconfigPrefix || base === tsconfigPrefix + '/index') {
          isBarePrefix = true;
          break;
        }
      }
      // If it matches a known wildcard prefix, skip (covered by prefixAliases)
      if (isBarePrefix && WILDCARD_PREFIXES[alias]) continue;

      exactLines.push({ alias, expr: targetToExpression(target) });
    }
  }

  const maxAliasLen = exactLines.reduce((m, l) => Math.max(m, l.alias.length), 0);

  const exactBlock = exactLines
    .map(({ alias, expr }) => {
      const pad = ' '.repeat(maxAliasLen - alias.length + 2);
      return `  '${alias}':${pad}${expr},`;
    })
    .join('\n');

  const wildcardBlock = wildcardLines
    .map(({ prefix, expr }) => `  '${prefix}': ${expr},`)
    .join('\n');

  const generated = `\
/**
 * AUTO-GENERATED by scripts/generate-register-aliases.js
 * Source of truth: tsconfig.electron.json compilerOptions.paths
 *
 * DO NOT EDIT MANUALLY. Run \`node scripts/generate-register-aliases.js\` to regenerate.
 *
 * Registers TypeScript path aliases for Node.js runtime resolution.
 * tsc does not rewrite path aliases in emitted JS; this module patches
 * Node's module resolver so require('@contracts/...') resolves correctly.
 *
 * MUST be required before any module that uses path aliases.
 */

import * as path from 'path';

const baseContracts = path.join(__dirname, '..', 'packages', 'contracts', 'src');
const baseSdk = path.join(__dirname, '..', 'packages', 'sdk', 'src');
const baseShared = path.join(__dirname, '..', 'shared');

const exactAliases: Record<string, string> = {
${exactBlock}
};

const prefixAliases: Record<string, string> = {
${wildcardBlock}
};

// eslint-disable-next-line @typescript-eslint/no-require-imports, @typescript-eslint/no-explicit-any
const NativeModule = require('module') as any;

const originalResolveFilename: (...args: unknown[]) => string =
  NativeModule._resolveFilename.bind(NativeModule);

function resolveFilename(request: string, ...rest: unknown[]): string {
  const exactTarget = exactAliases[request];
  if (exactTarget !== undefined) {
    return originalResolveFilename(exactTarget, ...rest);
  }
  for (const [alias, target] of Object.entries(prefixAliases)) {
    if (request === alias) {
      return originalResolveFilename(target, ...rest);
    }
    if (request.startsWith(alias + '/')) {
      return originalResolveFilename(
        path.join(target, request.slice(alias.length + 1)),
        ...rest,
      );
    }
  }
  return originalResolveFilename(request, ...rest);
}

Object.defineProperty(NativeModule, '_resolveFilename', {
  value: resolveFilename,
  writable: true,
  configurable: true,
});
`;

  fs.writeFileSync(OUTPUT_PATH, generated, 'utf-8');
  console.log(`generate-register-aliases: wrote ${exactLines.length} exact aliases and ${wildcardLines.length} prefix aliases to ${path.relative(ROOT, OUTPUT_PATH)}`);
}

main();
